+		/* Append header if it fits. */
+		int hlen = (int)strlen(buf);
+		if (reqlen + hlen < (int)sizeof(reqbuf) - 32)
+			reqlen += snprintf(reqbuf + reqlen,
+			    sizeof(reqbuf) - reqlen, "%s", buf);
+	}
+
+	/* Terminate with Connection: close and blank line. */
+	reqlen += snprintf(reqbuf + reqlen, sizeof(reqbuf) - reqlen,
+	    "Connection: close\r\n\r\n");
+
+	/* Connect to the end server. */
+	serverfd = open_clientfd(hostname, port);
+	if (serverfd < 0) {
+		client_error(connfd, hostname, 404, "Not Found",
+		    "Could not connect to the end server");
+		goto cleanup;
+	}
+
+	/* Forward the rewritten request to the server. */
+	if (rio_writen(serverfd, reqbuf, reqlen) < 0)
+		goto cleanup;
+
+	/*
+	 * Relay the server's response back to the client, counting the total
+	 * bytes so we can log the size.
