+		    (int)total_bytes);
+		pthread_mutex_lock(&log_mutex);
+		fprintf(log_file, "%s\n", log_entry);
+		fflush(log_file);
+		pthread_mutex_unlock(&log_mutex);
+		free(log_entry);
+	}
+
+cleanup:
+	if (serverfd >= 0)
+		close(serverfd);
+	free(hostname);
+	free(port);
+	free(pathname);
